#include "mpu6050_sensor.h"
#include <Wire.h>
#include <Adafruit_MPU6050.h>
#include <Adafruit_Sensor.h>
#include "config.h"

static Adafruit_MPU6050 _mpu;
static bool _mpuReady = false;
static sensors_event_t _accel, _gyro, _temp;

void mpu6050_setup() {
    Wire.begin(21, 22);
    Wire.setClock(400000); // 400kHz fast mode for IMU

    for (int i = 0; i < 5; i++) {
        if (_mpu.begin(0x68, &Wire)) {
            _mpuReady = true;
            break;
        }
        delay(100);
    }

    if (_mpuReady) {
        _mpu.setAccelerometerRange(MPU6050_RANGE_2_G);
        _mpu.setGyroRange(MPU6050_RANGE_250_DEG);
        _mpu.setFilterBandwidth(MPU6050_BAND_21_HZ);
        Serial.println("[mpu6050] IMU initialized");
    } else {
        Serial.println("[mpu6050] FAILED - check wiring!");
    }
}

void mpu6050_loop() {
    if (!_mpuReady) return;
    _mpu.getEvent(&_accel, &_gyro, &_temp);
}

float mpu6050_accel_x() { return _accel.acceleration.x; }
float mpu6050_accel_y() { return _accel.acceleration.y; }
float mpu6050_accel_z() { return _accel.acceleration.z; }
float mpu6050_gyro_x() { return _gyro.gyro.x * 57.2958f; }
float mpu6050_gyro_y() { return _gyro.gyro.y * 57.2958f; }
float mpu6050_gyro_z() { return _gyro.gyro.z * 57.2958f; }
float mpu6050_temperature() { return _temp.temperature; }
bool mpu6050_ready() { return _mpuReady; }

