#include "vl53l0x_sensor.h"
#include <Wire.h>
#include <VL53L0X.h>
#include "config.h"

static VL53L0X _tof;
static bool _tofReady = false;
static int _distanceMm = 0;
static bool _outOfRange = false;

void vl53l0x_setup() {
    Wire.begin(21, 22);
    _tof.setTimeout(500);
    if (_tof.init()) {
        _tofReady = true;
        _tof.setMeasurementTimingBudget(200000);
        _tof.startContinuous();
        Serial.println("[vl53l0x] ToF sensor ready");
    } else {
        Serial.println("[vl53l0x] FAILED");
    }
}

void vl53l0x_loop() {
    if (!_tofReady) return;
    uint16_t reading = _tof.readRangeContinuousMillimeters();
    if (_tof.timeoutOccurred()) {
        _outOfRange = true;
    } else {
        _outOfRange = (reading >= 8190);
        _distanceMm = reading;
    }
}

int vl53l0x_distance_mm() { return _distanceMm; }
bool vl53l0x_out_of_range() { return _outOfRange; }
bool vl53l0x_ready() { return _tofReady; }

