void audio_proc_setup();
void audio_proc_analyze(int32_t* samples, size_t count);
float audio_proc_get_dominant_freq();
float audio_proc_get_rms_db();
bool audio_proc_is_loud();

#endif
===SOURCE===
#include "audio_processor.h"
#include <arduinoFFT.h>
#include "config.h"

#define FFT_SIZE 1024

static double _vReal[FFT_SIZE];
static double _vImag[FFT_SIZE];
static float _dominantFreq = 0;
static float _rmsDb = -100.0f;
static bool _isLoud = false;
static const float NOISE_THRESHOLD = -40.0f;

ArduinoFFT<double> _fft(_vReal, _vImag, FFT_SIZE, 16000);

void audio_proc_setup() {
    Serial.println("[audio-proc] FFT processor ready");
}

void audio_proc_analyze(int32_t* samples, size_t count) {
    size_t n = min(count, (size_t)FFT_SIZE);
    // Fill FFT input
    float sumSq = 0;
    for (size_t i = 0; i < n; i++) {
        float s = (float)(samples[i] >> 14) / 32768.0f;
        _vReal[i] = s;
        _vImag[i] = 0;
        sumSq += s * s;
    }
    for (size_t i = n; i < FFT_SIZE; i++) {
        _vReal[i] = 0; _vImag[i] = 0;
    }

    // RMS in dB
    float rms = sqrt(sumSq / n);
    _rmsDb = (rms > 0) ? 20.0f * log10(rms) : -100.0f;
    _isLoud = _rmsDb > NOISE_THRESHOLD;

    // FFT
    _fft.windowing(FFTWindow::Hamming, FFTDirection::Forward);
    _fft.compute(FFTDirection::Forward);
    _fft.complexToMagnitude();
    _dominantFreq = _fft.majorPeak();
}

float audio_proc_get_dominant_freq() { return _dominantFreq; }
float audio_proc_get_rms_db() { return _rmsDb; }
bool audio_proc_is_loud() { return _isLoud; }

