#include "lvgl_app.h"
#include <TFT_eSPI.h>
#include "config.h"

#define SCREEN_W 320
#define SCREEN_H 240
#define BUF_LINES 40

static TFT_eSPI _tft(SCREEN_H, SCREEN_W);
static lv_disp_draw_buf_t _drawBuf;
static lv_color_t _buf1[SCREEN_W * BUF_LINES];
static lv_disp_drv_t _dispDrv;

static void _flush_cb(lv_disp_drv_t* drv, const lv_area_t* area, lv_color_t* color_p) {
    uint32_t w = area->x2 - area->x1 + 1;
    uint32_t h = area->y2 - area->y1 + 1;
    _tft.startWrite();
    _tft.setAddrWindow(area->x1, area->y1, w, h);
    _tft.pushColors((uint16_t*)&color_p->full, w * h, true);
    _tft.endWrite();
    lv_disp_flush_ready(drv);
}

void lvgl_app_setup() {
    _tft.begin();
    _tft.setRotation(1);
    lv_init();
    lv_disp_draw_buf_init(&_drawBuf, _buf1, NULL, SCREEN_W * BUF_LINES);
    lv_disp_drv_init(&_dispDrv);
    _dispDrv.hor_res = SCREEN_W;
    _dispDrv.ver_res = SCREEN_H;
    _dispDrv.flush_cb = _flush_cb;
    _dispDrv.draw_buf = &_drawBuf;
    lv_disp_drv_register(&_dispDrv);
    Serial.println("[lvgl] Display initialized");
}

void lvgl_app_loop() {
    lv_timer_handler();
}

lv_obj_t* lvgl_get_screen() { return lv_scr_act(); }

void lvgl_create_label(const char* text, int x, int y) {
    lv_obj_t* label = lv_label_create(lv_scr_act());
    lv_label_set_text(label, text);
    lv_obj_set_pos(label, x, y);
    lv_obj_set_style_text_color(label, lv_color_white(), 0);
}

void lvgl_update_label(lv_obj_t* label, const char* text) {
    lv_label_set_text(label, text);
}

lv_obj_t* lvgl_create_gauge(int x, int y, int w, int h, float min, float max) {
    lv_obj_t* bar = lv_bar_create(lv_scr_act());
    lv_obj_set_pos(bar, x, y);
    lv_obj_set_size(bar, w, h);
    lv_bar_set_range(bar, (int)min, (int)max);
    return bar;
}

void lvgl_update_gauge(lv_obj_t* bar, float value) {
    lv_bar_set_value(bar, (int)value, LV_ANIM_ON);
}

