    print_security_status();
}

bool is_secure_boot_enabled() {
    return esp_secure_boot_enabled();
}

bool is_flash_encrypted() {
    return esp_flash_encryption_enabled();
}

void print_security_status() {
    Serial.println("[security] === Security Status ===");
