#include "rtos_semaphore.h"

SemaphoreHandle_t rtos_mutex_create() {
    SemaphoreHandle_t m = xSemaphoreCreateMutex();
    if (m) Serial.println("[rtos-sem] Mutex created");
    return m;
}

SemaphoreHandle_t rtos_binary_sem_create() {
    SemaphoreHandle_t s = xSemaphoreCreateBinary();
    if (s) {
        xSemaphoreGive(s); // Start available
        Serial.println("[rtos-sem] Binary semaphore created");
    }
    return s;
}

bool rtos_sem_take(SemaphoreHandle_t sem, uint32_t timeoutMs) {
    if (!sem) return false;
    return xSemaphoreTake(sem, pdMS_TO_TICKS(timeoutMs)) == pdTRUE;
}

void rtos_sem_give(SemaphoreHandle_t sem) {
    if (sem) xSemaphoreGive(sem);
}

SemLock::SemLock(SemaphoreHandle_t sem, uint32_t timeoutMs)
    : _sem(sem), _acquired(false) {
    _acquired = rtos_sem_take(_sem, timeoutMs);
    if (!_acquired) Serial.println("[rtos-sem] WARNING: Lock timeout!");
}

SemLock::~SemLock() {
    if (_acquired) rtos_sem_give(_sem);
}

bool SemLock::acquired() const { return _acquired; }

