typedef void (*TaskFunction)(void);

TaskHandle_t rtos_create_task(const char* name, TaskFunction fn, uint32_t stackSize = 4096, 
                              UBaseType_t priority = 5, BaseType_t core = 1);
void rtos_delete_task(TaskHandle_t handle);
UBaseType_t rtos_stack_watermark(TaskHandle_t handle);
void rtos_task_delay(uint32_t ms);

