#ifndef UNIT_CONVERTER_H
#define UNIT_CONVERTER_H
#include <Arduino.h>

enum ConversionType {
    CONV_C_TO_F, CONV_F_TO_C,
    CONV_M_TO_FT, CONV_FT_TO_M,
    CONV_PA_TO_HPA, CONV_HPA_TO_PA,
    CONV_RAD_TO_DEG, CONV_DEG_TO_RAD,
    CONV_NONE
};

class UnitConverter {
public:
    UnitConverter(ConversionType type = CONV_NONE);
    float convert(float value);
    void setConversion(ConversionType type);
private:
    ConversionType _type;
};

#endif
===SOURCE===
#include "unit_converter.h"

UnitConverter::UnitConverter(ConversionType type) : _type(type) {}

float UnitConverter::convert(float value) {
    switch (_type) {
        case CONV_C_TO_F:    return value * 9.0f / 5.0f + 32.0f;
        case CONV_F_TO_C:    return (value - 32.0f) * 5.0f / 9.0f;
        case CONV_M_TO_FT:   return value * 3.28084f;
        case CONV_FT_TO_M:   return value / 3.28084f;
        case CONV_PA_TO_HPA: return value / 100.0f;
        case CONV_HPA_TO_PA: return value * 100.0f;
        case CONV_RAD_TO_DEG: return value * 180.0f / PI;
        case CONV_DEG_TO_RAD: return value * PI / 180.0f;
        default: return value;
    }
}

void UnitConverter::setConversion(ConversionType type) { _type = type; }

